import React, { useState, useEffect } from 'react';
import { MapContainer, TileLayer, Marker, Popup } from 'react-leaflet';
import { Search, MapPin, Navigation, ShoppingBag, Truck, Tag } from 'lucide-react';

const Home = () => {
  const [todasLasOfertas, setTodasLasOfertas] = useState([]);
  const [ofertasFiltradas, setOfertasFiltradas] = useState([]);
  const [filtro, setFiltro] = useState('');
  const [verMapa, setVerMapa] = useState(false);

  useEffect(() => {
    // 1. Cargamos todos los locales
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    let acumuladorOfertas = [];

    // 2. Recopilamos las ofertas de cada local para mostrarlas en el Home
    locales.forEach(local => {
      const ofertasLocal = JSON.parse(localStorage.getItem(`ofertas-local-${local.id}`) || "[]");
      const ofertasConInfoLocal = ofertasLocal.map(o => ({
        ...o,
        nombreLocal: local.nombre,
        coords: local.coords,
        direccion: local.direccion
      }));
      acumuladorOfertas = [...acumuladorOfertas, ...ofertasConInfoLocal];
    });

    setTodasLasOfertas(acumuladorOfertas);
    setOfertasFiltradas(acumuladorOfertas);
  }, []);

  // 3. Lógica de búsqueda optimizada
  useEffect(() => {
    const filtrado = todasLasOfertas.filter(o => 
      o.producto.toLowerCase().includes(filtro.toLowerCase())
    );
    setOfertasFiltradas(filtrado);
  }, [filtro, todasLasOfertas]);

  const abrirNavegacion = (coords) => {
    // Navegación gratuita basada en OpenStreetMap
    window.open(`https://www.openstreetmap.org/directions?engine=fossgis_osrm_car&route=%2C${coords[0]}%2C${coords[1]}`, '_blank');
  };

  return (
    <div style={{ background: '#f8fafc', minHeight: '90vh' }}>
      {/* SECCIÓN HERO CON BUSCADOR */}
      <div style={heroSection}>
        <h1 style={heroTitle}>¡Encuentra las mejores ofertas cerca tuyo!</h1>
        <div style={searchContainer}>
          <Search color="#94a3b8" />
          <input 
            type="text" 
            placeholder="Ej: Aceite, Leche, Cerveza..." 
            style={searchInput}
            value={filtro}
            onChange={(e) => setFiltro(e.target.value)}
          />
          <button style={btnToggleMap} onClick={() => setVerMapa(!verMapa)}>
            {verMapa ? "Ver Lista" : "Ver en Mapa"}
          </button>
        </div>
      </div>

      <div style={{ padding: '40px 8%' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '25px' }}>
          <h2 style={{ margin: 0 }}>Ofertas disponibles</h2>
          <span style={{ color: '#64748b' }}>{ofertasFiltradas.length} productos encontrados</span>
        </div>

        {verMapa ? (
          /* VISTA DE MAPA */
          <div style={mapWrapper}>
            <MapContainer center={[-26.816, -65.230]} zoom={13} style={{ height: '100%', width: '100%', borderRadius: '20px' }}>
              <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
              {ofertasFiltradas.map(o => (
                <Marker key={o.id} position={o.coords}>
                  <Popup>
                    <div style={{ padding: '5px' }}>
                      <strong>{o.producto}</strong> <br/>
                      <span style={{ color: '#e67e22', fontWeight: 'bold' }}>${o.precioNuevo}</span> <br/>
                      <small>{o.nombreLocal}</small>
                    </div>
                  </Popup>
                </Marker>
              ))}
            </MapContainer>
          </div>
        ) : (
          /* VISTA DE GRILLA */
          <div style={gridOfertas}>
            {ofertasFiltradas.map((o) => {
              const ahorro = Math.round(((o.precioViejo - o.precioNuevo) / o.precioViejo) * 100);
              return (
                <div key={o.id} style={cardOferta}>
                  <div style={badgeAhorro}>-{ahorro}%</div>
                  <div style={imgContainer}>
                    {o.imagen ? <img src={o.imagen} alt={o.producto} style={imgStyle} /> : <Tag size={40} color="#e2e8f0" />}
                  </div>
                  
                  <div style={{ padding: '15px' }}>
                    <h4 style={{ margin: '0 0 10px 0', fontSize: '1.1rem' }}>{o.producto}</h4>
                    <div style={{ display: 'flex', alignItems: 'baseline', gap: '8px' }}>
                      <span style={precioNuevo}>${o.precioNuevo}</span>
                      <span style={precioViejo}>${o.precioViejo}</span>
                    </div>

                    <div style={deliveryBox}>
                      <span style={deliveryTag}><ShoppingBag size={12} /> Retiro</span>
                      <span style={{...deliveryTag, background: '#e0f2fe', color: '#0369a1'}}><Truck size={12} /> Envío</span>
                    </div>

                    <div style={localInfo}>
                      <MapPin size={14} /> 
                      <span style={{ whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{o.nombreLocal}</span>
                    </div>

                    <button style={btnComoLlegar} onClick={() => abrirNavegacion(o.coords)}>
                      <Navigation size={14} /> ¿Cómo llegar?
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

/* --- ESTILOS MEJORADOS --- */
const heroSection = { background: '#1e293b', padding: '60px 5%', textAlign: 'center', display: 'flex', flexDirection: 'column', alignItems: 'center' };
const heroTitle = { color: 'white', fontSize: '2.2rem', marginBottom: '25px', fontWeight: '800' };
const searchContainer = { display: 'flex', alignItems: 'center', background: 'white', padding: '8px 8px 8px 20px', borderRadius: '18px', width: '100%', maxWidth: '700px', gap: '10px', boxShadow: '0 10px 30px rgba(0,0,0,0.2)' };
const searchInput = { border: 'none', outline: 'none', flex: 1, fontSize: '1rem' };
const btnToggleMap = { background: '#1e293b', color: 'white', border: 'none', padding: '12px 20px', borderRadius: '12px', fontWeight: 'bold', cursor: 'pointer' };

const gridOfertas = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', gap: '25px' };
const cardOferta = { background: 'white', borderRadius: '20px', overflow: 'hidden', boxShadow: '0 4px 15px rgba(0,0,0,0.05)', position: 'relative', border: '1px solid #f1f5f9' };
const imgContainer = { height: '160px', background: '#f8fafc', display: 'flex', justifyContent: 'center', alignItems: 'center', overflow: 'hidden' };
const imgStyle = { width: '100%', height: '100%', objectFit: 'cover' };

const badgeAhorro = { position: 'absolute', top: '12px', left: '12px', background: '#ef4444', color: 'white', padding: '5px 10px', borderRadius: '8px', fontSize: '0.8rem', fontWeight: 'bold', zIndex: 10 };
const precioNuevo = { fontSize: '1.5rem', fontWeight: '900', color: '#e67e22' };
